```class Solution {
public:
    int minInsertions(string s) {
        int countLeft = 0, countRight = 0;
        for (char c : s) {
            if (c == '(') {
                countLeft++;
            } else if (c == ')') {
                countRight++;
                if (countLeft > countRight) {
                    countLeft -= countRight;
                }
            }
        }
        return countLeft;
    }
};
```

